import { ipcMain, WebContents } from 'electron';
import * as net from 'net';

/**
 * IRC connection state
 */
interface IrcConnection {
  socket: net.Socket;
  webContents: WebContents;
  nick: string;
  server: string;
  port: number;
}

/**
 * Event types sent to renderer
 */
type IrcEvent =
  | { type: 'message'; channel: string; nick: string; text: string }
  | { type: 'join'; channel: string; nick: string }
  | { type: 'part'; channel: string; nick: string; reason?: string }
  | { type: 'nick'; oldNick: string; newNick: string }
  | { type: 'names'; channel: string; names: string[] }
  | { type: 'topic'; channel: string; topic: string }
  | { type: 'connected'; nick: string }
  | { type: 'error'; message: string }
  | { type: 'disconnected' }
  | { type: 'raw'; line: string };

/**
 * IRC command types
 */
type IrcCommand =
  | 'PRIVMSG'
  | 'JOIN'
  | 'PART'
  | 'QUIT'
  | 'NICK'
  | 'NOTICE'
  | 'PING'
  | 'ERROR';

/**
 * Parsed IRC message
 */
interface ParsedIrcMessage {
  prefix?: string;
  command: IrcCommand;
  params: string[];
  trailing?: string;
}

/**
 * Current IRC connection (module-level variable)
 */
let currentConnection: IrcConnection | null = null;

/**
 * Buffer for partial IRC lines
 */
let lineBuffer = '';

/**
 * Register IPC handlers for IRC functionality
 */
export function registerIrcIpc(): void {
  ipcMain.handle('irc-connect', handleIrcConnect);
  ipcMain.handle('irc-disconnect', handleIrcDisconnect);
  ipcMain.handle('irc-send-message', handleIrcSendMessage);
  ipcMain.handle('irc-join', handleIrcJoin);
  ipcMain.handle('irc-part', handleIrcPart);
  ipcMain.handle('irc-set-nick', handleIrcSetNick);
}

/**
 * Handle IRC connect request
 * @param event - IPC event
 * @param args - Connection parameters
 * @returns Promise with connection result
 */
async function handleIrcConnect(
  event: Electron.IpcMainInvokeEvent,
  args: {
    server: string;
    port: number;
    nick: string;
    username: string;
    realname: string;
    password?: string;
  }
): Promise<{ ok: true } | { error: string }> {
  if (currentConnection) {
    return { error: 'Already connected to an IRC server' };
  }

  const { server, port, nick, username, realname, password } = args;
  const webContents = event.sender;

  return new Promise((resolve) => {
    const socket = new net.Socket();
    currentConnection = { socket, webContents, nick, server, port };

    socket.on('connect', () => {
      // Send connection commands
      if (password) {
        socket.write(`PASS ${password}\r\n`);
      }
      socket.write(`NICK ${nick}\r\n`);
      socket.write(`USER ${username} 0 * :${realname}\r\n`);
    });

    socket.on('data', (data) => {
      lineBuffer += data.toString('utf8');
      processBuffer();
    });

