    });

    socket.on('close', () => {
      sendEvent({ type: 'disconnected' });
      cleanupConnection();
    });

    socket.connect(port, server);
    resolve({ ok: true });
  });
}

/**
 * Handle IRC disconnect request
 * @returns Promise with disconnect result
 */
async function handleIrcDisconnect(): Promise<{ ok: true } | { error: string }> {
  if (!currentConnection) {
    return { error: 'Not connected to an IRC server' };
  }

  return new Promise((resolve) => {
    const { socket } = currentConnection!;
    socket.write('QUIT :Goodbye\r\n');
    socket.destroy();
    resolve({ ok: true });
  });
}

